import pytest

def test_create_department_missing_mandatory_name_returns_400(
    manager_api_client,   # <fixture>: authenticated httpx client for manager role
):
    payload = {"description": "No name provided"}
    response = manager_api_client.post("/departments", json=payload)

    assert response.status_code == 400, (
        f"Expected 400 for missing name, got {response.status_code}: {response.text}"
    )
    body = response.json()
    errors = body.get("errors") or body.get("detail") or ""
    error_text = str(errors).lower()
    assert "name" in error_text, (
        f"Validation error should reference 'name' field; got: {errors}"
    )

import pytest

MAX_NAME_LEN = 100

def test_create_department_name_at_maximum_boundary_length(
    manager_api_client,   # <fixture>: authenticated httpx client for manager role
    cleanup_department,   # <fixture>: deletes department by id after test
):
    name_at_max = "D" * MAX_NAME_LEN
    resp_ok = manager_api_client.post(
        "/departments", json={"name": name_at_max, "description": "boundary test"}
    )
    assert resp_ok.status_code in (200, 201), (
        f"100-char name should succeed; got {resp_ok.status_code}: {resp_ok.text}"
    )
    entity_id = resp_ok.json().get("id")
    assert entity_id, "Entity id must be returned for boundary-valid name"
    cleanup_department(entity_id)

    name_over_max = "D" * (MAX_NAME_LEN + 1)
    resp_err = manager_api_client.post(
        "/departments", json={"name": name_over_max, "description": "over boundary"}
    )
    assert resp_err.status_code == 400, (
        f"101-char name should be rejected with 400; got {resp_err.status_code}"
    )

